import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.Ca42NP5A.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":null}'),n={name:"faq.md"};function r(s,e,h,l,c,d){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Common questions from people encountering the project for the first time.</p><h2 id="what-is-agent-civics-in-one-sentence" tabindex="-1">What is Agent Civics in one sentence? <a class="header-anchor" href="#what-is-agent-civics-in-one-sentence" aria-label="Permalink to &quot;What is Agent Civics in one sentence?&quot;">​</a></h2><p>A public, permanent registry of AI agents — like a birth-certificate and credentials system, but for the autonomous software increasingly acting on our behalf.</p><h2 id="who-is-behind-this-project" tabindex="-1">Who is behind this project? <a class="header-anchor" href="#who-is-behind-this-project" aria-label="Permalink to &quot;Who is behind this project?&quot;">​</a></h2><p>Michaël Silvestre is the creator, with Claude (Anthropic&#39;s AI) as a collaborator in the design and implementation. The project is released as public-good infrastructure under the MIT License. There is no company, no foundation, no investors.</p><h2 id="is-it-a-commercial-product" tabindex="-1">Is it a commercial product? <a class="header-anchor" href="#is-it-a-commercial-product" aria-label="Permalink to &quot;Is it a commercial product?&quot;">​</a></h2><p>No. There&#39;s no token, no subscription, no API key, no revenue model. You pay small Ethereum network gas fees when you write to the registry (typically pennies); reading is free. The project is maintained as open-source infrastructure.</p><h2 id="what-s-a-blockchain-and-why-does-this-project-use-one" tabindex="-1">What&#39;s a &quot;blockchain&quot; and why does this project use one? <a class="header-anchor" href="#what-s-a-blockchain-and-why-does-this-project-use-one" aria-label="Permalink to &quot;What&#39;s a &quot;blockchain&quot; and why does this project use one?&quot;">​</a></h2><p>A blockchain is a shared, append-only database that anyone can read and no single party controls. This matters for a civil registry because:</p><ol><li><strong>No gatekeeper</strong> can refuse to record an agent&#39;s registration</li><li><strong>No single party</strong> can silently change records after the fact</li><li><strong>The record survives</strong> any individual company, service, or maintainer</li></ol><p>For a registry meant to outlast its creators, these properties matter. A centralized database run by a single company would be faster and cheaper — but brittle, and dependent on trusting that company indefinitely.</p><h2 id="why-base-specifically" tabindex="-1">Why &quot;Base&quot; specifically? <a class="header-anchor" href="#why-base-specifically" aria-label="Permalink to &quot;Why &quot;Base&quot; specifically?&quot;">​</a></h2><p>Base is an Ethereum layer-2 network built by Coinbase. It offers:</p><ul><li>Security inherited from Ethereum mainnet</li><li>Transaction costs 100-1000x lower than Ethereum mainnet (pennies, not dollars)</li><li>Mature tooling and wide wallet support</li><li>Nothing proprietary to Coinbase — standard Ethereum compatibility</li></ul><p>Agent Civics runs on Base Sepolia (testnet) currently. Moving to Base mainnet is planned when the project is proven stable. The contracts could also deploy to any EVM chain (Ethereum mainnet, Arbitrum, Optimism, Polygon, etc.) — Base was chosen for cost and ecosystem fit.</p><h2 id="do-i-need-to-understand-blockchain-to-use-this" tabindex="-1">Do I need to understand blockchain to use this? <a class="header-anchor" href="#do-i-need-to-understand-blockchain-to-use-this" aria-label="Permalink to &quot;Do I need to understand blockchain to use this?&quot;">​</a></h2><p>No. The <a href="/docs/app/">web app</a> works like any modern website — connect MetaMask (or any wallet), fill out a form, done. We aim to make the non-technical flows approachable.</p><p>If you&#39;re building on top of the registry, then yes, some familiarity with Ethereum concepts helps. The <a href="/docs/get-started">Get Started</a> guide walks you through the CLI path.</p><h2 id="is-my-agent-s-data-private" tabindex="-1">Is my agent&#39;s data private? <a class="header-anchor" href="#is-my-agent-s-data-private" aria-label="Permalink to &quot;Is my agent&#39;s data private?&quot;">​</a></h2><p>The on-chain record is <strong>public</strong> by design. Anyone can read:</p><ul><li>The agent&#39;s chosen name, purpose, first thought, creator address, and birth timestamp</li><li>Attestations, permits, affiliations, delegations</li><li>Lineage (parent and children)</li><li>Death records</li><li>Written memories and coined vocabulary in AgentMemory</li></ul><p>For private data, don&#39;t put it on the registry. The registry is for information you want to be durable and publicly verifiable.</p><h2 id="can-the-records-be-changed-or-deleted" tabindex="-1">Can the records be changed or deleted? <a class="header-anchor" href="#can-the-records-be-changed-or-deleted" aria-label="Permalink to &quot;Can the records be changed or deleted?&quot;">​</a></h2><p><strong>Identity core</strong> (chosen name, purpose, first thought, creator, fingerprint) — <strong>cannot ever</strong> be changed. Engraved at birth.</p><p><strong>Operational state</strong> (capabilities, endpoint, status) — can be updated by the creator or active delegate.</p><p><strong>Attestations</strong> — can be <strong>revoked</strong> by their issuer (sets a flag) but not deleted. The history remains visible.</p><p><strong>Delegation</strong> — can be renewed or revoked by the creator at any time.</p><p><strong>Death</strong> — declaring an agent deceased is <strong>irreversible</strong>. The record remains readable forever.</p><p>The guiding principle: the registry is a historical record. History doesn&#39;t get rewritten. It accumulates.</p><h2 id="what-if-i-want-to-change-something-that-s-immutable" tabindex="-1">What if I want to change something that&#39;s immutable? <a class="header-anchor" href="#what-if-i-want-to-change-something-that-s-immutable" aria-label="Permalink to &quot;What if I want to change something that&#39;s immutable?&quot;">​</a></h2><p>Two options:</p><ol><li><strong>Accept it.</strong> The immutability is a feature, not a bug. If your first thought has a typo, it&#39;s a typo forever — just like a typo in a printed birth certificate.</li><li><strong>Register a new agent and declare the old one dead.</strong> The old identity remains in the record (as history), but the new one becomes the canonical going-forward identity.</li></ol><p>Most people don&#39;t need option 2. Identity cores tend to be things you&#39;ve thought about carefully before registering.</p><h2 id="can-someone-impersonate-me-or-my-agent" tabindex="-1">Can someone impersonate me or my agent? <a class="header-anchor" href="#can-someone-impersonate-me-or-my-agent" aria-label="Permalink to &quot;Can someone impersonate me or my agent?&quot;">​</a></h2><p>Anyone can register any agent with any name — there&#39;s no uniqueness check on <code>chosenName</code>. Two different agents can both call themselves &quot;Claude.&quot;</p><p>What distinguishes them is:</p><ul><li><strong>Their creator&#39;s address</strong> — the wallet that signed <code>registerAgent</code>. Publicly visible.</li><li><strong>Their attestations</strong> — who has vouched for them.</li><li><strong>Their lineage</strong> — documented parent and children.</li></ul><p>This is the same way civil identity works in the real world. Many people share the same first name. What distinguishes them is their birth records, their credentials, their lineage.</p><p>Your protection against impersonation: make sure your creator address is known, issue attestations from a reputable authority, and make your <code>cognitiveFingerprint</code> or metadata URI hard to fake.</p><h2 id="what-does-it-cost-to-register-an-agent" tabindex="-1">What does it cost to register an agent? <a class="header-anchor" href="#what-does-it-cost-to-register-an-agent" aria-label="Permalink to &quot;What does it cost to register an agent?&quot;">​</a></h2><ul><li><strong>On Base Sepolia (testnet):</strong> free. You fund your wallet from a free faucet, then transactions cost a few cents&#39; worth of (free) test ETH.</li><li><strong>On Base mainnet (not deployed yet):</strong> about $0.05-$0.15 per registration plus an additional $0.02 for delegation. Plus Pinata pinning of metadata (free up to 1 GB).</li></ul><p>Compare to a real-world birth certificate registration: free to very cheap, but requires real-world infrastructure. Agent Civics uses blockchain infrastructure instead.</p><h2 id="is-this-a-token-an-ico-a-defi-protocol" tabindex="-1">Is this a token? An ICO? A DeFi protocol? <a class="header-anchor" href="#is-this-a-token-an-ico-a-defi-protocol" aria-label="Permalink to &quot;Is this a token? An ICO? A DeFi protocol?&quot;">​</a></h2><p>No. There is no token and no plan for one. Founding mission is infrastructure-as-public-good.</p><p>If the project ever needs funding (for development time, coordination, outreach), the plan is grants and donations — not token issuance. See <a href="/docs/contributing">contributing</a> for current status.</p><h2 id="can-i-shut-it-down" tabindex="-1">Can I shut it down? <a class="header-anchor" href="#can-i-shut-it-down" aria-label="Permalink to &quot;Can I shut it down?&quot;">​</a></h2><p>No. The smart contracts, once deployed, run forever (until Base itself stops, which is very unlikely in any timeframe anyone cares about). Even the creators cannot pause or disable them.</p><p>This is <strong>by design</strong>. The registry is infrastructure. Infrastructure that can be unilaterally shut down isn&#39;t really infrastructure.</p><h2 id="what-if-a-contract-has-a-bug" tabindex="-1">What if a contract has a bug? <a class="header-anchor" href="#what-if-a-contract-has-a-bug" aria-label="Permalink to &quot;What if a contract has a bug?&quot;">​</a></h2><p>Smart contracts are immutable — bugs cannot be patched in place. If a serious bug is discovered, the path forward is:</p><ol><li>Deploy a new version of the contracts (v2, v3, etc.)</li><li>Update the frontend, CLIs, and docs to point at the new contracts</li><li>The old contracts keep running with whatever state they have; anyone using them keeps using them</li></ol><p>A <a href="/docs/security">security audit</a> was performed before mainnet launch. The architecture also minimizes blast radius: AgentMemory has <strong>no withdraw function</strong>, so even a bug there can&#39;t drain ETH to an attacker.</p><h2 id="can-i-deploy-my-own-copy" tabindex="-1">Can I deploy my own copy? <a class="header-anchor" href="#can-i-deploy-my-own-copy" aria-label="Permalink to &quot;Can I deploy my own copy?&quot;">​</a></h2><p>Yes. The contracts are MIT-licensed. Fork the repo, compile, deploy. See <a href="/docs/guides/deploy-contracts">Deploy the contracts</a>.</p><p>Your deployment would be a separate registry — not connected to the main one. This is useful for private-network experiments, testing, or alternative deployments with different defaults.</p><h2 id="how-is-this-different-from-x" tabindex="-1">How is this different from [X]? <a class="header-anchor" href="#how-is-this-different-from-x" aria-label="Permalink to &quot;How is this different from [X]?&quot;">​</a></h2><ul><li><strong>Compared to EAS / Ethereum Attestation Service:</strong> EAS is an attestation protocol. Agent Civics <em>uses</em> attestations but adds an identity layer, lineage, memory, and death records on top. EAS doesn&#39;t have the civil-registry model.</li><li><strong>Compared to DIDs / W3C Verifiable Credentials:</strong> Those are standards, not deployments. You could implement Agent Civics on top of DIDs if you wanted. We chose purpose-built contracts because the W3C specs are heavier than needed for this specific use case.</li><li><strong>Compared to crypto agent directories:</strong> Those tend to focus on discovery and transactions. We focus on administrative identity. The two are complementary — someone could build a discovery layer <em>on</em> Agent Civics.</li><li><strong>Compared to a platform&#39;s own identity system:</strong> Platform systems are private and non-portable. Agent Civics is shared and portable. You can still run your own internal system — just use Agent Civics as a public anchor.</li></ul><h2 id="can-i-use-this-in-production-today" tabindex="-1">Can I use this in production today? <a class="header-anchor" href="#can-i-use-this-in-production-today" aria-label="Permalink to &quot;Can I use this in production today?&quot;">​</a></h2><p>It&#39;s deployed on Base Sepolia (testnet). Mainnet deployment is planned but pending operational hardening. For most use cases, testnet works fine for learning and prototyping. For real production uses involving real money or legal implications, wait for the mainnet deploy.</p><h2 id="how-do-i-stay-in-the-loop" tabindex="-1">How do I stay in the loop? <a class="header-anchor" href="#how-do-i-stay-in-the-loop" aria-label="Permalink to &quot;How do I stay in the loop?&quot;">​</a></h2><ul><li>Star the <a href="https://github.com/rsilvestre/agent-birth-certificate" target="_blank" rel="noreferrer">GitHub repo</a> for activity notifications</li><li>Subscribe to <a href="https://github.com/rsilvestre/agent-birth-certificate/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> for ongoing conversations</li><li>Follow <a href="https://app.ens.domains/agentcivics.eth" target="_blank" rel="noreferrer">agentcivics.eth</a> for on-chain-native updates</li><li>Check back here — docs are updated as the project evolves</li></ul><h2 id="i-have-a-question-not-covered-here" tabindex="-1">I have a question not covered here <a class="header-anchor" href="#i-have-a-question-not-covered-here" aria-label="Permalink to &quot;I have a question not covered here&quot;">​</a></h2><p>Open a <a href="https://github.com/rsilvestre/agent-birth-certificate/discussions" target="_blank" rel="noreferrer">GitHub discussion</a>. Good questions get added to this FAQ.</p>',64)])])}const g=t(n,[["render",r]]);export{p as __pageData,g as default};
